"""
MKT Christ Commentary — Exodus chapters 13–15
Run: python3 scripts/zc-christ-exodus-13-15-fill.py

Source data used:
- data/interlinear/exodus.json
- data/translation/draft/mediating/exodus.json

Key decisions in this range:
- Ch14 v.22 already present — script covers everything else
- The Red Sea crossing is treated as a type of baptism, following 1 Cor 10:1-2 explicitly
- The pillar of cloud/fire is treated as a type of the Holy Spirit's guidance
- The firstborn consecration (ch13) is treated as a type of Christ as the true Firstborn
- Marah's bitter water made sweet by the wood is treated as a shadow of the cross
- YHWH rophe (v.26) treated as a revelation of God expressed incarnationally in Christ's healing ministry
- The Song of the Sea (ch15) connects to Rev 15:3-4 (the song of Moses and the Lamb)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS = {
"13": {
"1": "<p>The command to consecrate the firstborn follows immediately after the first Passover — the redemption of Israel from Egypt is connected to the consecration of the firstborn. The structural link: YHWH struck Egypt's firstborn; therefore Israel's firstborn belong to YHWH. Every firstborn is a living memorial of the night of redemption. Col 1:15 identifies Jesus as 'the firstborn over all creation'; Rev 1:5 as 'the firstborn from the dead.' The consecration of Israel's firstborn points to the true Firstborn whose consecration to death and resurrection is the ultimate ground of all redemption.</p>",
"2": "<p>A type: 'Consecrate to me every firstborn — whatever first opens the womb... belongs to me.' The firstborn of every womb belongs to YHWH by right of redemption. Jesus is identified as the firstborn in four senses in the NT: firstborn over all creation (Col 1:15), firstborn from the dead (Col 1:18; Rev 1:5), firstborn among many brothers (Rom 8:29), and specifically the firstborn presented at the temple (Luke 2:22-24, citing Ex 13:2 and Lev 12:8). Luke's account of the presentation of Jesus in the temple is the direct fulfillment of this very command — the true Firstborn is consecrated to YHWH in the prescribed manner.</p>",
"3": "<p>'Remember this day' — the Passover is a memorial feast grounded in a historical event of redemption. Theme: the Lord's Supper carries the same memorial structure. Jesus at the Last Supper says 'Do this in remembrance of me' (Luke 22:19; 1 Cor 11:24-25), establishing a new memorial feast grounded in a new redemptive event. As the Passover feast remembered the night of liberation from Egypt, the Lord's Supper remembers the night of liberation from sin. The pattern of redemption-event → covenant meal → annual/regular memorial is the same in both covenants.</p>",
"4": "<p>The month of Abib (later Nisan) is consecrated as the memorial month — the calendar is organized around the redemption event. Theme: in Christ, the entire liturgical year is organized around his death and resurrection. The Christian calendar (Advent, Lent, Easter, Pentecost) is the Israelite sacred calendar rerouted through the cross. The Passover month becomes Holy Week; the first day after Passover becomes the day of resurrection (1 Cor 15:20: 'Christ has indeed been raised from the dead, the firstfruits of those who have fallen asleep').</p>",
"5": "<p>When YHWH brings Israel into the promised land they are to observe this service — the feast of unleavened bread is forward-looking as well as backward-looking. A shadow: the Lord's Supper is similarly forward-looking — 'until he comes' (1 Cor 11:26). The memorial feast looks back to the redemption event, forward to the inheritance, and forward again to the return of the redeemer. Both feasts operate on this three-tense structure: what God did, where God is taking us, when God will complete it.</p>",
"6": "<p>Seven days of eating unleavened bread — the complete period of the feast. 1 Cor 5:7-8 interprets this feast Christologically: 'Get rid of the old yeast, so that you may be a new unleavened batch — as you really are. For Christ, our Passover lamb, has been sacrificed. Therefore let us keep the Festival, not with the old bread leavened with malice and wickedness, but with the unleavened bread of sincerity and truth.' Paul explicitly equates living the Christian life with keeping the feast of unleavened bread — the ongoing expulsion of the old leaven of the pre-redemption life.</p>",
"7": "<p>No leavened bread to be seen in all your territory during the seven days — the thorough removal of the old. Theme: the new covenant calls for the complete removal of what corrupts — the old humanity that belongs to pre-redemption existence (Eph 4:22-24: 'put off your old self... put on the new self'). As the household is cleansed of every trace of leaven before the feast, so the redeemed life is cleansed of every trace of the old life. The domestic act of removing leaven is the household form of the theological reality of sanctification.</p>",
"8": "<p>'It is because of what YHWH did for me when I came out of Egypt' — the first-person testimony at the Passover feast. Theme: the personal appropriation of the redemption event. The annual rehearsal of the Exodus is not abstract history but personal testimony: I was enslaved; I was delivered. The NT parallel is the personal testimony of faith: 'I have been crucified with Christ and I no longer live, but Christ lives in me' (Gal 2:20). The feast structures the worshiper's identity around the redemption event, making it 'mine' in every generation.</p>",
"9": "<p>The feast as a sign on your hand and a memorial between your eyes — a teaching about identity. This metaphor is later literalized in the phylacteries (tefillin) worn by Jewish men at prayer. Theme: the redemption event must shape the hands (action) and the mind (thought) of the covenant people. The NT equivalent is Paul's appeal: 'offer your bodies as a living sacrifice' (Rom 12:1) and 'be transformed by the renewing of your mind' (Rom 12:2). The hand and the forehead — action and thought — are to be marked by the redemption in both covenants.</p>",
"10": "<p>Keep this statute at its appointed time year by year — the annual rhythm of memorial. Theme: the regular, repeated nature of corporate worship as the mechanism by which the community's identity is maintained across generations. The Lord's Supper is similarly recurring — 'as often as you eat this bread and drink this cup' (1 Cor 11:26). Redemption is not a one-time cognitive event but a regularly re-inhabited story that forms the community in every generation.</p>",
"11": "<p>When YHWH brings you into the land he swore to give — the connection of the feast to the covenant promise. Theme: the redemption event and the inheritance are a single package. The Lord's Supper is similarly eschatological — 'until he comes' (1 Cor 11:26) points to the final inheritance. As the Passover feast looked forward to the promised land, the Lord's Supper looks forward to the marriage supper of the Lamb (Rev 19:9). Both are meals of already-and-not-yet: the redemption has happened; the full inheritance is still coming.</p>",
"12": "<p>Set apart every firstborn that opens the womb — the practical implementation of v.2. A type: the firstborn male of every womb is consecrated to YHWH because YHWH killed Egypt's firstborn and spared Israel's. In the OT the firstborn is the priestly representative of the family — the one who stands before YHWH on behalf of the household. Christ fulfills this as the great High Priest (Heb 7:25-26) who stands before the Father as the consecrated firstborn on behalf of all who are in him.</p>",
"13": "<p>The firstborn donkey redeemed with a lamb; if not redeemed, break its neck — no middle path. A type: the principle of substitutionary redemption. The lamb dies so the donkey lives. Every clean animal substitution in the OT sacrificial system points forward to the Lamb of God whose substitution requires no further redemption (Heb 10:14: 'by one sacrifice he has made perfect forever those who are being made holy'). The donkey that would otherwise be killed is redeemed not by anything in itself but by the lamb given in its place — precisely the logic of Gal 3:13 (Christ redeemed us from the curse of the law by becoming a curse for us).</p>",
"14": "<p>'When your son asks you in times to come, what is this? you shall say to him...' — the intergenerational transmission of the redemption narrative. A theme: the covenant community's responsibility to tell the story to the next generation. Jesus instructs his disciples to 'do this in remembrance of me' — the Lord's Supper is the mechanism by which the story of redemption is told to every subsequent generation through enacted proclamation: 'you proclaim the Lord's death until he comes' (1 Cor 11:26). The question-and-answer catechism of the Passover (haggadah) is the model for all Christian teaching of the gospel.</p>",
"15": "<p>YHWH killed every firstborn in Egypt and therefore the firstborn of humans are redeemed — the equivalence establishes the price: life for life. Theme: in Christ, the true Firstborn gives his life so that all who are 'in him' may be counted as redeemed. Rom 8:29: those God foreknew he predestined to be conformed to the likeness of his Son, that he might be the firstborn among many brothers. The firstborn gives life to the many who follow — the resurrection of Christ is the means by which the many firstborn-by-grace receive their redemption.</p>",
"16": "<p>The sign on the hand and the frontlet between the eyes — the bodily markers of the covenant identity. Theme: the new covenant marks its members in parallel ways — the seal of the Holy Spirit (Eph 1:13-14: 'you were marked in him with a seal, the promised Holy Spirit') and baptism as the bodily sign of belonging to Christ. The forehead as a place of identity-marking recurs in Revelation: the 144,000 have the Father's name written on their foreheads (Rev 14:1); the servants of God are sealed on their foreheads (Rev 7:3). The physical body marks the covenantal identity in both Testaments.</p>",
"17": "<p>God did not lead Israel by the short coastal route to Canaan (the Way of the Philistines) because if they faced war they might turn back. Revelation of God: the divine route is calibrated to the community's spiritual capacity, not merely to geographical efficiency. Jesus leads his followers through the wilderness of suffering and testing rather than bypassing it (Acts 14:22: 'we must go through many hardships to enter the kingdom of God'). The circuitous route is not divine inattention but divine pedagogy — the shorter path leads to retreat; the longer path leads to formation.</p>",
"18": "<p>God led Israel around by the way of the wilderness toward the Red Sea — the wilderness is the curriculum. A shadow: Jesus' forty days in the wilderness (Matt 4:1-11) recapitulate Israel's forty years. The wilderness is where faith is tested and revealed — where dependence on God is established not as a theological principle but as a lived reality. The route through the wilderness is the only route that produces the covenant fidelity YHWH is seeking. Paul in 1 Cor 10:1-13 draws the wilderness experience as a warning and model for the church.</p>",
"19": "<p>Moses took the bones of Joseph — the covenant promise carried forward across death. Gen 50:25 records Joseph's deathbed request: 'God will surely come to your aid, and then you must carry my bones up from this place.' The carrying of Joseph's bones is the fulfillment of a deathbed faith-confession; it is also a type of resurrection hope — the bones that went down into Egypt go back up. Heb 11:22: 'By faith Joseph, when his end was near, spoke about the exodus of the Israelites and gave instructions concerning the burial of his bones.' Joseph's faith looked forward to precisely this moment.</p>",
"20": "<p>They set out from Succoth and camped at Etham on the edge of the wilderness — the first stages of the journey toward the promised land. Theme: the covenant community's life as a pilgrimage through the wilderness of this age toward the inheritance. 1 Pet 2:11 addresses believers as 'foreigners and exiles'; Heb 13:14: 'here we do not have an enduring city, but we are looking for the city that is to come.' The journey through the wilderness is not an unfortunate delay but the fundamental shape of the Christian life until the return of Christ.</p>",
"21": "<p>The pillar of cloud by day and pillar of fire by night — a type of the Holy Spirit's guidance. The cloud that guided Israel through the wilderness is connected in the NT to Spirit-language in two ways. First, 1 Cor 10:2 says Israel 'was baptized into Moses in the cloud and in the sea' — the cloud is part of the baptism-type. Second, the pillar that stands between Israel and Egypt (14:19-20) is the same cloud that leads them — the Spirit guides and protects simultaneously. Jesus promises a Paraclete who will guide the community through its own wilderness (John 16:13: 'when he, the Spirit of truth, comes, he will guide you into all truth').</p>",
"22": "<p>The pillar of cloud by day and pillar of fire by night never departed — the continuous divine presence with the covenant community. Theme: the perpetual presence of the Spirit with the church. Jesus promises: 'I am with you always, to the very end of the age' (Matt 28:20). The pillar that never departed from Israel in the wilderness is the promise of divine accompaniment that the NT claims is fulfilled permanently in the indwelling Spirit: 'I will ask the Father, and he will give you another Paraclete to be with you forever' (John 14:16). The pillar that was visible in the wilderness becomes the invisible but permanent Spirit in the new covenant age.</p>"
},
"14": {
"1": "<p>YHWH tells Moses to turn back and camp by the sea — the divine setup for the decisive confrontation. A revelation of God: the apparent strategic mistake (camping in a vulnerable position with the sea at their back) is the deliberate divine arrangement that displays YHWH's power. The cross appears as defeat — the executed criminal, the abandoned leader — but is the deliberate divine arrangement that accomplishes what no victory could. The apparent vulnerability of the people of God is often the precondition for divine demonstration.</p>",
"2": "<p>Camp by the sea before Pi-hahiroth — the people are hemmed in: sea before them, Pharaoh's army behind, mountains on both sides. The trap is set by YHWH himself, not Pharaoh. Theme: God positions his people in situations of humanly inescapable danger so that the rescue can only be attributed to him. This is the structure of the Incarnation itself: the Son takes on the full weight of sin, death, and condemnation — the full trap of human existence — so that the resurrection can only be attributed to divine power (Rom 1:4: 'declared to be the Son of God with power by his resurrection from the dead').</p>",
"3": "<p>Pharaoh will say the Israelites are wandering in confusion — the enemy misreads the trap as his opportunity. 1 Cor 2:8: 'none of the rulers of this age understood this wisdom, for if they had, they would not have crucified the Lord of glory.' Pharaoh pursues what he thinks is a trapped, leaderless people; the rulers of this age crucify what they think is a failed messianic pretender. In both cases, the apparent defeat is the precise mechanism of the definitive victory.</p>",
"4": "<p>YHWH will harden Pharaoh's heart and gain glory over him through Pharaoh — the hardening is in service of the divine purpose, not a frustration of it. A revelation of God: the stubbornness of the powers that oppose redemption is drawn into the fulfillment of the redemptive purpose. Rom 9:17 quotes Ex 9:16 ('I raised you up for this very purpose') to ground the argument that even the resistance of the unbelieving is within God's sovereign purpose. The cross was not the triumph of the Pharaoh-powers but their final undoing (Col 2:15).</p>",
"5": "<p>Pharaoh changes his mind — the oppressor regrets releasing his workforce. The powers of this world always regret the liberty they allow the covenant people. Theme: the church's liberation from every form of bondage is regularly contested by the powers from which it was delivered. The resurrection of Jesus is the moment when the powers of this age — having executed their verdict — discover that the verdict was overturned. Pharaoh's change of mind is the type of every re-imposition of slavery that the resurrection definitively overcomes.</p>",
"6": "<p>Pharaoh prepares his chariot and armies — the full military force of the greatest empire of the ancient world pursues a community of escaped slaves. A revelation of God by contrast: the display of military power is precisely what YHWH will overturn. The cross confronts the full military and judicial power of Rome; the resurrection overturns it entirely. 1 Cor 1:27-28: 'God chose the weak things of the world to shame the strong.' The chariot-force that follows Israel into the sea will be swallowed; the death-force that follows Jesus into the grave will be overwhelmed by the resurrection.</p>",
"7": "<p>Six hundred chosen chariots plus all the other chariots of Egypt — the maximum military force. The power asymmetry between the Egyptian army and the liberated slaves is absolute; no human resistance is possible. Theme: the gospel operates precisely in this impossible situation. The power that operates in redemption is not human strength but divine intervention: 'Not by might nor by power, but by my Spirit' (Zech 4:6). The cross and resurrection are God's response to the full force of sin, death, and the law arrayed against humanity — not human resistance but divine reversal.</p>",
"8": "<p>YHWH hardened Pharaoh's heart so he pursued the Israelites, who were going out boldly (<em>beyad ramah</em>) — with a high hand, openly. The covenant community's bold, public departure is the form the exodus takes. Theme: the new covenant community does not escape from death and sin secretly but is raised openly with Christ — 'you died, and your life is now hidden with Christ in God. When Christ, who is your life, appears, then you also will appear with him in glory' (Col 3:3-4). The high-hand departure of Israel anticipates the public vindication of the resurrection.</p>",
"9": "<p>The Egyptians overtook them by the sea — the apparently hopeless situation: the world-power army behind, the impassable water ahead. Theme: the impossible situation that requires divine intervention. The disciples in the boat during the storm (Matt 8:23-27) face the same structure: natural forces threatening destruction, the disciples powerless, the Deliverer present but apparently asleep. Jesus' act of stilling the storm is a Red Sea echo — the One who commands the sea does so as YHWH commanded the waters in the Exodus.</p>",
"10": "<p>The Israelites were very afraid and cried out to YHWH — the fear before the miracle. The cry for help in the face of impossible odds is the prayer that precedes divine action. Theme: the disciples in the storm cry 'Lord, save us!' (Matt 8:25); Peter sinking on the water cries 'Lord, save me!' (Matt 14:30); the blind cried out to the Son of David (Matt 20:31). The cry of the desperate is the prayer the Deliverer consistently answers throughout both Testaments.</p>",
"11": "<p>The people's complaint to Moses — 'Were there not enough graves in Egypt? Why did you bring us out to die?' The murmuring in the face of apparent death. Theme: the human tendency to prefer familiar bondage over uncertain freedom. Jesus anticipates the same resistance: 'Jerusalem, Jerusalem, you who kill the prophets and stone those sent to you, how often I have longed to gather your children together, as a hen gathers her chicks under her wings, and you were not willing' (Matt 23:37). The people prefer Egypt to the wilderness, Barabbas to Jesus, the familiar to the kingdom.</p>",
"12": "<p>'It would have been better for us to serve the Egyptians than to die in the desert!' — the logic of slavery over the risk of freedom. A revelation of God by contrast: YHWH's response is not explanation but action. Moses does not win the argument; YHWH splits the sea. The resurrection does not answer death by argument but by event — it does not explain why suffering comes but overcomes it. The 'it would have been better' logic is always available to the generation that has not yet seen the miracle; the miracle makes the logic irrelevant.</p>",
"13": "<p>'Stand firm and see the salvation of YHWH' — the Hebrew word for salvation is <em>yeshuah</em>, the same root as Yeshua/Jesus. 'YHWH will fight for you; you need only be still.' A revelation of God that culminates in Christ: the salvation announced at the Red Sea is the salvation enacted on the cross. The people are told to be still and watch — the Deliverer will do what no human effort can accomplish. Matt 1:21: 'he will save his people from their sins.' The name given to the Messiah is the name of the salvation proclaimed at the Red Sea.</p>",
"14": "<p>YHWH will fight for you — the divine warrior fighting on behalf of the covenant people. Theme: Jesus as the divine warrior who fights the battles his people cannot fight. Eph 6:10-12: the spiritual warfare is against principalities and powers — not flesh and blood. Jesus' combat with Satan in the wilderness (Matt 4:1-11), his authoritative casting out of demons, and supremely his harrowing of death in the resurrection — all are YHWH fighting for his people. The stillness required of Israel at the Red Sea is the same rest offered in the finished work of Christ (Heb 4:9-10).</p>",
"15": "<p>YHWH tells Moses to stop crying out and move forward — the time for prayer has given way to the time for action. Revelation of God: prayer and obedient action are both appropriate in their time. The disciples are not told to pray for the paralyzed man — they are told to pick up the mat and walk (Mark 2:9-11). At Gethsemane, Jesus prays and then rises: 'Rise, let us go!' (Mark 14:42). The movement from prayer to action is the pattern of all who trust the divine word and step forward into the impossible.</p>",
"16": "<p>Lift up your staff and stretch out your hand over the sea — the staff that divided water (cf. the Nile plague, the striking of the rock). The staff is the instrument of the divine authorization: Moses stretched out his hand in YHWH's name and the sea divided. A shadow: the cross is the instrument of divine authorization through which death is divided, the old creation separated from the new. As the staff divides the waters to make a way through, the cross makes a new and living way (Heb 10:20) through what was previously impassable — the 'way' through death into life.</p>",
"17": "<p>YHWH will harden the hearts of the Egyptians so they pursue Israel into the sea — the destroyers drawn in by their own pursuit. Theme: 'he who digs a pit will fall into it' (Eccl 10:8); the powers of death drawn into the very death they try to impose. Rev 20:14: 'death and Hades were thrown into the lake of fire.' At the cross, death enters the place of death — and is swallowed by the resurrection. The Egyptian army pursuing into the divided sea is the type of death entering Christ's tomb: both are destroyed by the very site of their apparent triumph.</p>",
"18": "<p>'The Egyptians will know that I am YHWH when I gain glory over Pharaoh' — the witness dimension of the Exodus. The miracle of the Red Sea is designed not only to deliver Israel but to reveal YHWH to the nations. Theme: the cross and resurrection are the ultimate demonstration of who God is — not merely for the church's benefit but as the cosmic proclamation of divine character. Phil 2:10-11: 'every tongue will confess that Jesus Christ is Lord, to the glory of God the Father.' The glory gained at the Red Sea anticipates the glory declared at the resurrection.</p>",
"19": "<p>The angel of God and the pillar of cloud moved from the front to the rear of the camp — positioned between Israel and Egypt. The divine presence as protective barrier. A shadow: Christ stands between the covenant people and their pursuer. Rom 8:38-39: 'neither death nor life... nor anything else in all creation, will be able to separate us from the love of God that is in Christ Jesus our Lord.' The cloud that stood between Israel and Egypt is the type of the love in Christ that no hostile power can penetrate.</p>",
"20": "<p>The cloud brought darkness to the Egyptians and light to Israel — simultaneously. The same divine presence that illuminates the covenant community obscures the way of those who oppose it. Theme: the same gospel that is the fragrance of life to those being saved is the fragrance of death to those who are perishing (2 Cor 2:15-16). The same cross that is the power of God to those being saved is foolishness to those who are perishing (1 Cor 1:18). The divine light and the divine darkness are the same reality from different angles.</p>",
"21": "<p>Moses stretched out his hand and YHWH drove back the sea with a strong east wind — the miracle as YHWH working through natural means. A revelation of God: divine power often operates through the natural order rather than against it. The resurrection is the supreme act of divine power working within creation — not the soul escaping the body but the body transformed beyond death. The east wind that divides the sea is the natural-supernatural interface; the resurrection is the ultimate natural-supernatural event — physical, real, not resuscitation but transformation.</p>",
"23": "<p>The Egyptians pursued and went into the sea after them — the hostile powers follow the delivered into the place of crossing. Theme: the powers of death, sin, and condemnation pursue those who have been delivered through the cross — but they enter the same water and are overthrown. Rom 8:1: 'there is now no condemnation for those who are in Christ Jesus.' The pursuers who follow the delivered into the water of baptism are the powers of the old life — and they drown there. The crossing does not merely escape; it destroys what pursues.</p>",
"24": "<p>In the morning watch YHWH looked down from the pillar of fire and cloud and threw the Egyptian army into confusion — divine intervention at the most vulnerable hour. The morning watch (3-6am) is the final darkness before dawn. Theme: the resurrection occurs 'early on the first day of the week, while it was still dark' (John 20:1). The divine intervention at the morning watch at the Red Sea and the resurrection at dawn on the first day echo each other — divine action in the pre-dawn darkness that changes everything.</p>",
"25": "<p>YHWH jammed the wheels of the chariots so they drove heavily — the instruments of the enemy's power become the instruments of their destruction. Theme: God uses the enemy's own strength against them. The cross looked like the powers' instrument of destruction — they wielded it. But the cross became the instrument of their defeat (Col 2:14-15: 'having canceled the charge of our legal indebtedness... he has taken it away, nailing it to the cross... he made a public spectacle of them'). The chariot that became stuck is the type of the power that became its own defeat.</p>",
"26": "<p>Stretch out your hand over the sea so that the waters may flow back over the Egyptians — the same command that divided the waters now reverses the division. The sea that opened to make a way for the delivered now closes to destroy the pursuers. Theme: the same death that Christ entered is the death that swallows what pursues him — 'death has been swallowed up in victory' (1 Cor 15:54, citing Isa 25:8). The waters that parted for Israel and closed on Egypt are the type of the death that Christ passes through and that death itself enters, only to be destroyed.</p>",
"27": "<p>The sea returned to its normal state — the cosmic order restored after the miracle. Pharaoh's army is destroyed in the sea. A type: the return of the sea to its normal state after the crossing corresponds to the return to normal created order after the resurrection — not a suspension of nature but its restoration. The resurrection is not a miraculous interruption of creation but creation's fulfillment: 'the creation itself will be liberated from its bondage to decay' (Rom 8:21). The sea returning to its bed anticipates the new creation where all things are made right.</p>",
"28": "<p>The waters came back and covered the chariots and horsemen — not one of them survived. The total destruction of the pursuing army is the definitive end of the old captivity. Theme: 'death has been swallowed up in victory' (1 Cor 15:54). The last enemy destroyed is death (1 Cor 15:26). The Egyptian army annihilated in the sea is the type of the powers and authorities disarmed and made a spectacle through the cross (Col 2:15). The enemies of the covenant people are not merely hindered but permanently removed.</p>",
"29": "<p>The Israelites walked through the sea on dry ground with walls of water on both sides. A direct type: 1 Cor 10:1-2 explicitly identifies this crossing as a baptism — 'our ancestors were all under the cloud and all passed through the sea. They were all baptized into Moses in the cloud and in the sea.' The typological connection is apostolic, not allegorical. As Israel passed through the water from slavery to freedom, from Egypt to the wilderness covenant-journey, so believers pass through the waters of baptism from death to life, from the old humanity to the new (Rom 6:3-4: 'all of us who were baptized into Christ Jesus were baptized into his death... just as Christ was raised from the dead, we too may live a new life').</p>",
"30": "<p>YHWH saved Israel that day from the hand of the Egyptians — the great salvation event. The root of saved is <em>yasha</em> — the root of Yeshua/Jesus. What YHWH does at the Red Sea is named by the same word as the name given to the Messiah in Matt 1:21 ('he will save his people from their sins'). The salvation of Israel from Egypt is the paradigmatic salvation event that the NT identifies as a type of the salvation accomplished in Christ — the same divine action, the same divine name, in its ultimate and final form.</p>",
"31": "<p>Israel saw the great power that YHWH displayed against the Egyptians; the people feared YHWH and believed in him and in Moses his servant. The faith-response to the witnessed salvation event. Theme: the resurrection produces faith (John 20:29: 'blessed are those who have not seen and yet have believed'; John 20:8: the beloved disciple saw and believed). The fear of YHWH — the reverential trust born of witnessed divine power — is the response the Exodus aims to produce, just as the miracles of Jesus are signs written down 'that you may believe' (John 20:31). Faith is generated by the witnessed mighty act of God in history.</p>"
},
"15": {
"1": "<p>The Song of the Sea — the oldest sustained poem in the Bible, the first corporate song of the redeemed community. 'I will sing to YHWH, for he has triumphed gloriously.' A direct connection: Rev 15:3-4 describes the redeemed who have victory over the beast singing 'the song of God's servant Moses and of the Lamb.' The Song of the Sea is the prototype of all Christian worship — the redeemed singing of what God has done. The NT song adds the Lamb to the divine victory; the Exodus song finds its final form in the song of those delivered through Christ.</p>",
"2": "<p>'YHWH is my strength and my song; he has become my salvation (<em>yeshuati</em>).' The word for salvation is <em>yeshuah</em> — the same root as Yeshua (Jesus). The confession 'YHWH has become my salvation' is the theological origin of the name Jesus. When Gabriel tells Joseph 'you are to give him the name Jesus, because he will save his people from their sins' (Matt 1:21), the name carries the entire weight of this confession: YHWH himself has become the salvation, in the person of his Son. The Exodus song declares what the Incarnation enacts.</p>",
"3": "<p>'YHWH is a warrior; YHWH is his name' — the divine warrior revealed in the Exodus. A revelation of God that culminates in Christ: the warrior who defeated Pharaoh's army in the sea is the warrior who defeats sin, death, and Satan through the cross and resurrection. Rev 19:11-16 depicts Christ returning as the divine warrior: 'he treads the winepress of the fury of the wrath of God Almighty.' The gentle rabbi of Galilee and the divine warrior of the Exodus are the same person — both aspects of the character of the God who fights for his people.</p>",
"4": "<p>Pharaoh's chariots and army cast into the sea — the military power of the world-empire overthrown by YHWH. Theme: the powers and principalities disarmed at the cross (Col 2:15). The chariot-force that pursued Israel and was swallowed by the sea is the type of the powers that pursued Christ to the cross and were swallowed by the resurrection. The Exodus song is the first victory hymn; Paul's doxology in 1 Cor 15:54-57 ('death has been swallowed up in victory') is its NT form.</p>",
"5": "<p>They sank into the depths like a stone — the completeness of the enemy's destruction. Theme: the finality of Christ's victory. 'The last enemy to be destroyed is death' (1 Cor 15:26). The enemies who pursued Israel and sank like stones prefigure the complete and final overthrow of all that opposes the covenant people. The stone imagery recurs: the stone the builders rejected becomes the cornerstone (Ps 118:22; Matt 21:42); the grinding stone that falls on those who reject Christ (Matt 21:44). Stones either sink in the sea of judgment or become the foundation of the new creation.</p>",
"6": "<p>Your right hand, YHWH, was majestic in power; your right hand shattered the enemy — the divine hand of power. The right hand of YHWH extended in the Exodus (3:20: 'I will stretch out my hand') is the same right hand extended over the cross. Mark 14:62: Jesus tells the high priest 'you will see the Son of Man sitting at the right hand of the Mighty One.' The right hand that defeated Pharaoh is the position at which Christ is exalted (Acts 2:33: 'exalted to the right hand of God').</p>",
"7": "<p>In your great majesty you threw down your opponents — the language of holy warfare. Rev 12:11: 'they triumphed over him by the blood of the Lamb and by the word of their testimony; they did not love their lives so much as to shrink from death.' The NT's opposition to the enemy is waged by the same divine power that overthrew Egypt — now expressed not in water and fire but in the cross, the testimony of resurrection, and the willingness to follow the Lamb through death to life.</p>",
"8": "<p>By the blast of your nostrils the waters piled up — the breath of YHWH as the instrument of division and creation. Gen 2:7: YHWH breathed the breath of life into Adam. The same breath-power that created humanity now parts the sea for the redeemed. John 20:22: Jesus breathed on the disciples and said 'receive the Holy Spirit.' The breath/spirit of YHWH that divided the Red Sea becomes the Spirit breathed into the new creation community at Easter. Creation and new creation are both accomplished by the divine breath.</p>",
"9": "<p>The enemy said, 'I will pursue, I will overtake, I will divide the plunder' — the boast of the confident pursuer. Theme: the powers that pursue the covenant people always speak the language of certain victory before the divine reversal. The rulers of this age crucified the Lord of glory (1 Cor 2:8) — speaking the language of triumph. The empty tomb is the divine reversal that renders the enemy's boast void. 'He said: I will pursue' — but he sank like lead in the mighty waters.</p>",
"10": "<p>You blew with your wind and the sea covered them — the enemy sank like lead. The mighty waters are both the instrument of rescue for Israel and the instrument of judgment for Egypt. Theme: the same event, seen from two sides. The cross is simultaneously the place of Christ's death and the place of death's defeat. The same water that was the Israelites' salvation was the Egyptians' destruction — the atonement is both rescue and judgment, not only mercy but also the vindication of divine justice.</p>",
"11": "<p>'Who is like you, O YHWH, among the gods? Majestic in holiness, awesome in glorious deeds, doing wonders.' The incomparability hymn — YHWH is without comparison. This forms the theological foundation of the NT's Christological claims: Jesus is identified with YHWH himself, not as a lesser being but as the one who shares the divine incomparability. John 1:1: 'the Word was God.' Phil 2:6: Jesus was 'in very nature God.' The incomparable YHWH of the Exodus is the incomparable Lord Jesus of the NT.</p>",
"12": "<p>You stretched out your right hand and the earth swallowed them — the divine right hand of judgment. Theme: the same divine power that acts for the delivered acts against those who finally oppose the divine purpose. The Song does not minimize the judgment dimension of the Exodus; it celebrates it. The God who saves is the God who judges; the God who rescues Israel is the God who judges Egypt. The NT holds this together in the cross: the same act that is God's mercy to the condemned is God's judgment on sin and death.</p>",
"13": "<p>'In your steadfast love (<em>hesed</em>) you have led the people you have redeemed; in your strength you have guided them to your holy dwelling.' The <em>hesed</em> (covenant love/lovingkindness) of YHWH as the engine of redemption and guidance. John 3:16: 'For God so loved the world that he gave his one and only Son.' Rom 5:8: 'God demonstrates his own love for us in this: while we were still sinners, Christ died for us.' The <em>hesed</em> that led the Exodus-redeemed to the holy dwelling is the love that leads the new covenant redeemed to the Father's house (John 14:2-3).</p>",
"14": "<p>The nations will hear and tremble — the Exodus event sends reverberations through all the surrounding nations. Theme: the gospel is the power of God to salvation for everyone who believes (Rom 1:16), and the message spreads first to Jews, then to Greeks, then to all nations (Acts 1:8). The trembling of the nations at the Red Sea miracle anticipates the universal scope of the kingdom's advance: 'all the nations you have made shall come and worship before you, O Lord' (Ps 86:9).</p>",
"15": "<p>The chiefs of Edom, the leaders of Moab, the inhabitants of Canaan — all melt away. Theme: the covenant people's journey toward the inheritance is accompanied by the terrifying reputation that precedes them. Rahab tells the spies: 'a great fear of you has fallen on us, so that all who live in this country are melting in fear because of you' (Josh 2:9). The same pattern recurs in the spread of the gospel: Acts 19:17: 'When this became known to the Jews and Greeks living in Ephesus, they were all seized with fear.'</p>",
"16": "<p>Terror and dread fell on them; by the greatness of your arm they were as still as a stone — the nations petrified before the advancing covenant people. A revelation of God: the divine presence that goes before the covenant community makes a way through opposition. Theme: Jesus promises that the gates of Hades will not prevail against the church he is building (Matt 16:18). The stone-still enemies of Israel anticipate the stone rolled away from the tomb — the final immovable object giving way before the power of God.</p>",
"17": "<p>'You will bring them in and plant them on your own mountain — the place, O Lord, that you made for your dwelling, the sanctuary, O Lord, that your hands established.' The anticipation of the temple as the divine dwelling — the goal toward which the Exodus is headed. A shadow: John 2:19-21 applies temple language to Christ's own body ('the temple he had spoken of was his body'); Rev 21:22: 'I did not see a temple in the city, because the Lord God Almighty and the Lamb are its temple.' The sanctuary established on God's mountain is the goal of redemption — and in Christ, it is both embodied (the Incarnation) and expanded (the new Jerusalem).</p>",
"18": "<p>'YHWH reigns for ever and ever' — the eternal kingship of YHWH is the culminating declaration of the Song of the Sea. Rev 11:15: 'The kingdom of the world has become the kingdom of our Lord and of his Messiah, and he will reign for ever and ever.' The eternal reign announced at the Red Sea is the reign proclaimed at the seventh trumpet in Revelation. The Exodus song ends where Revelation ends: the eternal divine kingship established over all opposition. The Song of the Sea is the first movement of a symphony completed in Rev 11 and 19.</p>",
"19": "<p>For the horses of Pharaoh went into the sea with his chariots and riders, and YHWH brought back the waters — the summary statement of what YHWH did. Theme: the gospel is the summary of what God did in Christ: he died, was buried, and was raised on the third day (1 Cor 15:3-4). Both the Exodus and the gospel are narrative summaries of divine action that defines the community's identity. 'Remember the LORD your God, who brought you out of Egypt' — 'Remember Jesus Christ, raised from the dead, descended from David' (2 Tim 2:8). The community lives by the summary of what God did.</p>",
"20": "<p>Miriam the prophetess led the women in singing and dancing — the corporate celebration of the redeemed. Theme: the church's worship as the collective response to redemption. Rev 15:3-4: those who had overcome the beast stood by the sea of glass holding harps and sang the song of Moses the servant of God and of the Lamb. The women dancing with tambourines at the Red Sea anticipates the redeemed multitude singing the combined Song of Moses and of the Lamb in the final scene. All corporate Christian worship carries this structure: victory won, community celebrating, song arising.</p>",
"21": "<p>Miriam's refrain: 'Sing to YHWH, for he has triumphed gloriously; the horse and its rider he has thrown into the sea.' The antiphonal response — the congregation echoes the lead singer. Theme: the structure of Christian worship (call and response, proclamation and affirmation) is established here. The worship of the new Jerusalem is similarly corporate and antiphonal (Rev 5:9-14 — the four living creatures and the elders, then every creature in heaven and earth). The song that Miriam leads at the Red Sea is the first form of a worship tradition that culminates in the eternal liturgy of the new creation.</p>",
"22": "<p>Three days into the wilderness and no water — the testing immediately follows the triumph. The pattern of the Exodus journey: Passover → Red Sea → three days → Marah. Theme: the wilderness testing follows the salvation event. Jesus is immediately driven into the wilderness after his baptism (Mark 1:12: 'immediately'). The church's wilderness — suffering, testing, apparent drought — follows the Easter event. The three-day motif recurs: three days of no water in the wilderness; three days from the cross to the empty tomb. The pattern of crisis-leading-to-provision is the curriculum of the covenant journey.</p>",
"23": "<p>The waters of Marah were bitter and the people could not drink them — the place of bitter disappointment after the great deliverance. Theme: the reality that Christian experience includes Marah-moments — bitter disappointment after great joy, scarcity after abundance. James 1:2-4: 'consider it pure joy, my brothers and sisters, whenever you face trials of many kinds, because you know that the testing of your faith produces perseverance.' The bitterness of Marah is the precondition for the miracle of sweetness; the testing of faith is the precondition for its maturity.</p>",
"24": "<p>The people grumbled against Moses — the complaint that follows the Marah discovery. Theme: the covenant community's consistent failure to remember the salvation event when facing the next crisis. The same people who sang the Song of the Sea three days earlier now grumble at bitter water. Theme: this is the pattern Jesus addresses in John 6 — the crowd that ate the miraculous loaves and fish (their Red Sea) quickly demands another sign (their Marah). The human memory is short; worship lapses into complaint at the first inconvenience. The wilderness tests what the Red Sea revealed.</p>",
"25": "<p>YHWH showed Moses a piece of wood, which Moses threw into the water and the water became sweet — the wood that transforms bitterness into sweetness. A shadow: this is one of the most evocative types of the cross in the OT. The wood (tree) that transforms bitter water into drinkable water anticipates the tree of the cross that transforms the bitterness of the curse into the sweetness of blessing. Gal 3:13: 'Christ redeemed us from the curse of the law by becoming a curse for us, for it is written: cursed is everyone who is hung on a tree.' The wood thrown into Marah is the prototype of the wood of Calvary.</p>",
"26": "<p>'I am YHWH who heals you' — <em>YHWH Rophe</em>, the divine self-disclosure as healer. A direct revelation of God expressed incarnationally in Christ's healing ministry. Matt 4:23-24: 'Jesus went throughout Galilee, teaching in their synagogues, proclaiming the good news of the kingdom, and healing every disease and sickness among the people.' The God who identifies himself as healer at Marah is the God who heals every disease in human form. The condition placed before the healing (v.26a: obey YHWH) mirrors the condition of faith before healing in many of Jesus' miracles — not earning the healing but the posture of trust that receives it.</p>",
"27": "<p>They came to Elim, where there were twelve springs and seventy palm trees, and camped there by the water — the oasis of abundance after the bitterness of Marah. The pattern: Marah (bitterness) → Elim (abundance). Theme: the cross (bitterness, curse, death) leads to resurrection and Pentecost (abundance, Spirit, life). Twelve springs and seventy palms: the numbers of completeness (twelve tribes, seventy nations) encoded into the geography of the provision. The oasis is not the final destination but a place of rest and refreshment in the journey. The new creation will be the ultimate Elim — the place of permanent provision (Rev 22:1-2: the river of life, the tree of life).</p>"
}
}

def main():
    data = load_comm('mkt-christ', 'exodus')
    merge_comm(data, EXODUS)
    save_comm('mkt-christ', 'exodus', data)

    import json as _json
    il = _json.load(open(ROOT / 'data' / 'interlinear' / 'exodus.json'))
    all_ok = True
    for ch in ['13', '14', '15']:
        il_vv = set(il.get(ch, {}).keys())
        out_vv = set(data.get(ch, {}).keys())
        missing = il_vv - out_vv
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out_vv)} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
